# -*- coding: utf-8 -*-
"""
游戏静态数据种子包

功能：将所有游戏静态数据以 gzip + base64 形式内嵌?Python 模块中，
彻底消除?JSON 文件的运行时依赖?

数据在导入时自动解压?Python 对象，供初始化脚本使用?

对应已删除的 JSON 文件?
- bdcode_skills.json          ->  _BD_SKILLS_DATA
- bdcode_specializations.json ->  _BD_SPECIALIZATIONS_DATA
- bdcode_traits.json          ->  _BD_TRAITS_DATA
- skill_palettes.json         ->  _SKILL_PALETTES_DATA
- buffs.json                  ->  _BUFFS_DATA
- builds_initial_data.json    ->  _BUILDS_INITIAL_DATA

作? System
创建日期: 22026-05-12
"""

import base64
import gzip
import json
from typing import Any, Dict, List


def _decompress(name: str, data: bytes) -> Any:
    """解压 base64 + gzip 数据并返?Python 对象"""
    cleaned = b"".join(data.split())
    decoded = base64.b64decode(cleaned)
    decompressed = gzip.decompress(decoded)
    return json.loads(decompressed)


